B.JM=new A.b5("pda_palindrome","PDA Palindromes","Build a PDA over {a, b} that accepts even-length palindromes (ww^R where w is any string over {a,b}).\nHint: push the first half onto the stack, then pop-match the second half.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|a\n      n0 to n0 = b,\u2205|b\n      n0 to n1 = \u2205,\u2205|\u2205\n      n1 to n1 = a,a|\u2205\n      n1 to n1 = b,b|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aT,B.mr,0.8,"pda")
B.Jz=new A.b5("pda_more_as","More a's Than b's","Build a PDA over {a, b} that accepts strings where the number of a's is strictly greater than the number of b's (in any order).\nPush for each a, pop for each b; accept if the stack is non-empty at the end.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (380.0, 360.0)\n      n1 = (720.0, 360.0)\n      n2 = (1060.0, 360.0)\n      n0 to n0 = a,\u2205|X\n      n0 to n0 = b,X|\u2205\n      n0 to n1 = \u2205,X|X\n      n1 is accepted\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aT,B.mr,0.25,"pda")
B.JF=new A.b5("pda_an_b2n","a\u207fb\xb2\u207f","Build a PDA that accepts strings of the form a\u207fb\xb2\u207f (n \u2265 1): for every a there must be exactly two b's.\nHint: push two markers for each a you read.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|X\n      n0 to n0 = a,\u2205|X\n      n0 to n1 = b,X|\u2205\n      n1 to n1 = b,X|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aT,B.mr,0.5,"pda")
B.Ol=s(["pda_palindrome","pda_more_as"],t.s)
B.TE=new A.fV(B.Ol)
B.Jx=new A.b5("level_2","Level 2 \u2014 PDA Boss","Build a PDA that matches the hidden stack-based target machine. Study the transition format and think carefully about what language this could be.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = <<ha>>\n      n4 = E\n      n5 = F\n      n0 = (723.3, 204.7)\n      n1 = (1139.3, 259.3)\n      n2 = (1196.0, 527.3)\n      n3 = (739.3, 705.3)\n      n4 = (345.3, 504.7)\n      n5 = (345.3, 277.3)\n      n0 to n5 = 0,~|X\n      n0 to n1 = 1,~|Y\n      n1 to n1 = 1,~|Y\n      n1 to n2 = 0,Y|~\n      n2 to n1 = 1,\u2205|Y\n      n2 to n5 = 0,\u2205|X\n      n4 to n1 = 1,\u2205|Y\n      n4 to n5 = 0,\u2205|X\n      n5 to n4 = 1,X|~\n      n5 to n5 = 0,~|X\n      n4 to n4 = 1,X|~\n      n4 to n3 = \u2205,\u2205|~\n      n2 to n3 = \u2205,\u2205|~\n      n2 to n2 = 0,Y|~\n      l0(0,~|X) curve = -2.9\n      l3(0,Y|~) curve = 62.2\n      l4(1,\u2205|Y) curve = 55.1\n      l5(0,\u2205|X) curve = 39.9\n      l6(1,\u2205|Y) curve = 16.9\n      l7(0,\u2205|X) curve = -8.2\n      l8(1,X|~) curve = -105.4\n      l2(1,~|Y) loop angle = -0.7988\n      l9(0,~|X) loop angle = -1.5708\n      l10(1,X|~) loop angle = 1.7686\n      l13(0,Y|~) loop angle = -0.0754\n      to n0 angle = -1.0000, 0.0000\n    ",B.aT,B.TE,0.5,"pda")
