B.JG=new A.b5("level_3","Level 3 \u2014 TM Boss","Build a Turing machine that matches the hidden target tape behaviour. This is the hardest TM puzzle \u2014 study the state transitions carefully.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.1, 194.6)\n      B = (1233.4, 154.6)\n      C = (772.1, 630.0)\n      D = (460.1, 504.0)\n      E = (765.4, 454.0)\n      F = (758.1, 255.9)\n      B is accepted\n      F is accepted\n      E to F = \u2205\u2205S\n      A to F = \u2205\u2205S\n      C to E = \\0\\0R\n      C to C = XXL\n      D to D = aaL\n      B to B = aaR\n      B to B = XXR\n      B to C = bXL\n      C to D = aaL\n      D to A = XXR\n      A to B = aXR\n      E to E = XXR\n      l0(\u2205\u2205S) curve = 4.2\n      l1(\u2205\u2205S) curve = -75.2\n      bXL curve = 103.8\n      l7(aaL) curve = 40.7\n      l8(XXR) curve = 53.9\n      aXR curve = 61.8\n      XXL loop angle = 1.5107\n      l4(aaL) loop angle = 2.2185\n      aaR loop angle = -1.5708\n      l10(XXR) loop angle = 3.3847\n      to A angle = -1.0000, 0.0000\n    ",B.aG,B.TB,0.65,"tm")
